const input = $input.first().json;
const run = input.run || input;
const metrics = run.output_metrics_json || input.output_metrics_json || {};
const stages = metrics.stages || {};
const metricSummary = {
  stage_order: metrics.stage_order || [],
  stage_keys: Object.keys(stages),
  identity_events_processed: (stages.identity_resolution || {}).events_processed ?? null,
  scoring_rows_written: (stages.intent_scoring || {}).rows_written ?? null,
  attribution_opportunities_processed: (stages.opportunity_attribution || {}).opportunities_processed ?? null
};
return [{
  json: {
    status: run.status || input.status || 'unknown',
    run_id: run.run_id || input.run_id || null,
    job_name: run.job_name || input.job_name || null,
    trigger_source: run.trigger_source || input.trigger_source || null,
    started_at: run.started_at || input.started_at || null,
    completed_at: run.completed_at || input.completed_at || null,
    duration_ms: run.duration_ms || input.duration_ms || null,
    error_message: run.error_message || input.error_message || 'No error_message supplied',
    output_metrics_json: metrics,
    metric_summary: metricSummary,
    notification_webhook_url: input.notification_webhook_url || 'https://example.com/replace-with-slack-or-email-webhook'
  }
}];
